// inferred-not-tested:default export = NightingaleMSA 类;消费方注册 custom element
import NightingaleMSA from 'https://cdn.jsdelivr.net/npm/@nightingale-elements/nightingale-msa@5.6.0/+esm';
if (!customElements.get('nightingale-msa')) customElements.define('nightingale-msa', NightingaleMSA);
const msa = document.createElement('nightingale-msa');
msa.setAttribute('width', String(data.width ?? 600));
msa.setAttribute('height', String(data.height ?? 200));
msa.setAttribute('label-width', String(data.labelWidth ?? 100));
if (data['color-scheme']) msa.setAttribute('color-scheme', data['color-scheme']);
document.getElementById('msa').appendChild(msa);
customElements.whenDefined('nightingale-msa').then(() => { msa.data = data.sequences; });

